To thoroughly test the `is_valid_email` function, we can write a series of unit tests using the `pytest` framework. These tests will cover the happy path (valid email addresses), edge cases (such as emails with unusual but valid characters), and error cases (invalid email formats). Here's how you can structure these tests:

```python
import pytest
from your_module import is_valid_email  # Replace 'your_module' with the actual module name

# Happy path tests
def test_valid_email_simple():
    assert is_valid_email("test@example.com") == True

def test_valid_email_with_numbers():
    assert is_valid_email("user123@example.com") == True

def test_valid_email_with_dots():
    assert is_valid_email("first.last@example.com") == True

def test_valid_email_with_plus():
    assert is_valid_email("user+name@example.com") == True

def test_valid_email_with_subdomain():
    assert is_valid_email("user@mail.example.com") == True

def test_valid_email_with_hyphen():
    assert is_valid_email("user-name@example.com") == True

# Edge case tests
def test_valid_email_minimal_domain():
    assert is_valid_email("user@e.co") == True

def test_valid_email_max_tld_length():
    assert is_valid_email("user@example.museum") == True

def test_valid_email_with_underscore():
    assert is_valid_email("user_name@example.com") == True

# Error case tests
def test_invalid_email_no_at_symbol():
    assert is_valid_email("userexample.com") == False

def test_invalid_email_no_domain():
    assert is_valid_email("user@.com") == False

def test_invalid_email_no_username():
    assert is_valid_email("@example.com") == False

def test_invalid_email_double_at_symbol():
    assert is_valid_email("user@@example.com") == False

def test_invalid_email_special_characters():
    assert is_valid_email("user!@example.com") == False

def test_invalid_email_space_in_address():
    assert is_valid_email("user @example.com") == False

def test_invalid_email_no_tld():
    assert is_valid_email("user@example") == False

def test_invalid_email_tld_too_short():
    assert is_valid_email("user@example.c") == False

def test_invalid_email_tld_too_long():
    assert is_valid_email("user@example.comm") == False

def test_invalid_email_start_with_dot():
    assert is_valid_email(".user@example.com") == False

def test_invalid_email_end_with_dot():
    assert is_valid_email("user.@example.com") == False

def test_invalid_email_double_dot():
    assert is_valid_email("user..name@example.com") == False

# Run the tests
if __name__ == "__main__":
    pytest.main()
```

### Explanation:
- **Happy Path Tests**: These tests check for typical valid email formats, including those with numbers, dots, plus signs, subdomains, and hyphens.
- **Edge Case Tests**: These tests cover less common but still valid scenarios, such as minimal domain names and underscores in the username.
- **Error Case Tests**: These tests ensure that the function correctly identifies invalid email formats, such as missing components, invalid characters, and incorrect TLD lengths.

Make sure to replace `'your_module'` with the actual name of the module where the `is_valid_email` function is defined. You can run these tests using the `pytest` command in your terminal.
